import { createDOMElem } from "domelemjs";
import { highlightCode } from "./highlighter";
export function createCodeBlock(params) {
    const children = [];
    const copyable = params.copyable !== false;
    const hasLanguage = !!params.language;
    // Header row: language label + copy button
    if (hasLanguage || copyable) {
        const headerChildren = [];
        if (hasLanguage) {
            headerChildren.push({
                tag: "span",
                text: params.language.toUpperCase(),
                attrs: { class: "code-language" },
            });
        }
        if (copyable) {
            headerChildren.push({
                tag: "button",
                attrs: {
                    class: "code-copy-btn",
                    type: "button",
                    "data-code": params.code,
                },
                text: "Copy",
                handleEvent: {
                    event: "click",
                    cb: (e) => {
                        const btn = e.currentTarget;
                        const code = btn.getAttribute("data-code") || "";
                        navigator.clipboard.writeText(code).then(() => {
                            btn.textContent = "Copied!";
                            setTimeout(() => {
                                btn.textContent = "Copy";
                            }, 2000);
                        }).catch(() => {
                            /* clipboard write failed — silently ignore */
                        });
                    },
                },
            });
        }
        children.push({
            tag: "div",
            attrs: { class: "code-header" },
            children: headerChildren,
        });
    }
    const highlighted = highlightCode(params.code, params.language);
    children.push({
        tag: "pre",
        attrs: { class: "code-pre" },
        children: [
            {
                tag: "code",
                content: highlighted,
                attrs: { class: `code-content${params.language ? ` language-${params.language}` : ""}` },
            },
        ],
    });
    const rootAttrs = {
        class: `code-block${params.class ? ` ${params.class}` : ""}`,
    };
    if (params.id)
        rootAttrs.id = params.id;
    const opts = {
        tag: "div",
        attrs: rootAttrs,
        children,
    };
    if (params.parent)
        opts.parent = params.parent;
    return createDOMElem(opts);
}
