import { createDOMElem } from "domelemjs";
export function createBadge(params) {
    const rootAttrs = { class: `badge badge-${params.type || "neutral"}${params.class ? ` ${params.class}` : ""}` };
    if (params.id)
        rootAttrs.id = params.id;
    return createDOMElem({ tag: "span", parent: params.parent, attrs: rootAttrs, text: params.text });
}
