import { createDOMElem } from "domelemjs";
export function asyncImage(params) {
    const attrs = {
        src: params.src,
        alt: params.alt || "",
        class: `async-image${params.class ? ` ${params.class}` : ""}`,
    };
    if (params.lazy)
        attrs.loading = "lazy";
    return createDOMElem({
        tag: "img",
        parent: params.parent,
        attrs,
    });
}
