import { createDOMElem } from "domelemjs";
export function createContainer(params) {
    const rootAttrs = { class: `container${params.class ? ` ${params.class}` : ""}` };
    if (params.id)
        rootAttrs.id = params.id;
    return createDOMElem({ tag: "div", parent: params.parent, attrs: rootAttrs, children: params.children });
}
